// Parser for test result files in JUnit XML and JSON formats
export interface ParsedResult {
  tests: number;
  passed: number;
  failed: number;
  skipped: number;
  duration: number;
}

// Parse JUnit XML format test results
export function parseJunitXml(xmlContent: string): ParsedResult {
  let tests = 0;
  let passed = 0;
  let failed = 0;
  let skipped = 0;
  let totalDuration = 0;

  // Simple XML parsing - extract testsuites and their attributes
  const suiteRegex = /<testsuite[^>]*>/g;
  let match;

  while ((match = suiteRegex.exec(xmlContent)) !== null) {
    const suiteTag = match[0];

    // Extract attributes from testsuite
    const timeMatch = suiteTag.match(/time="([^"]+)"/);
    if (timeMatch) {
      totalDuration += parseFloat(timeMatch[1]);
    }
  }

  // Count test cases by status
  const testCaseRegex = /<testcase[^>]*>(?:.*?(?=<\/testcase>))*<\/testcase>/gs;
  while ((match = testCaseRegex.exec(xmlContent)) !== null) {
    const testCaseBlock = match[0];
    tests++;

    if (testCaseBlock.includes("<failure")) {
      failed++;
    } else if (testCaseBlock.includes("<skipped")) {
      skipped++;
    } else {
      passed++;
    }
  }

  return { tests, passed, failed, skipped, duration: totalDuration };
}

// Parse JSON format test results
export function parseJsonResults(jsonContent: string): ParsedResult {
  const data = JSON.parse(jsonContent);

  let passed = 0;
  let failed = 0;
  let skipped = 0;
  let totalDuration = 0; // in milliseconds

  if (Array.isArray(data.tests)) {
    for (const test of data.tests) {
      totalDuration += test.duration || 0;

      if (test.status === "passed") {
        passed++;
      } else if (test.status === "failed") {
        failed++;
      } else if (test.status === "skipped") {
        skipped++;
      }
    }
  }

  const tests = data.tests ? data.tests.length : 0;

  // Convert milliseconds to seconds
  const durationInSeconds = totalDuration / 1000;

  return { tests, passed, failed, skipped, duration: durationInSeconds };
}

