  tests: number;
  passed: number;
  failed: number;
  skipped: number;
  duration: number;
}

// Parse JUnit XML format test results
export function parseJunitXml(xmlContent: string): ParsedResult {
  let tests = 0;
  let passed = 0;
  let failed = 0;
  let skipped = 0;
  let totalDuration = 0;

  // Extract testsuite duration
  const suiteRegex = /time="([^"]+)"/g;
  let match;

  // First, collect all duration values from testsuites
  const tempContent = xmlContent;
  let suiteIndex = 0;

  for (match of tempContent.matchAll(/time="([^"]+)"/g)) {
    // Check if this is a testsuite time attribute (appears before testcases)
    const beforeText = tempContent.substring(0, match.index);
    const testcaseCountBefore = (beforeText.match(/<testcase/g) || []).length;
    const testsuitesCountBefore = (beforeText.match(/<testsuite/g) || []).length;

    // If no testcases before this position, it's a testsuite time
    if (testcaseCountBefore === 0 && testsuitesCountBefore > 0) {
      totalDuration += parseFloat(match[1]);
    }
  }

  // Count test cases by status - more precise regex
  const testCaseRegex = /<testcase[^>]*>([\s\S]*?)<\/testcase>/g;

  while ((match = testCaseRegex.exec(xmlContent)) !== null) {
    tests++;
    const testCaseContent = match[1];

    if (testCaseContent.includes("<failure")) {
      failed++;
    } else if (testCaseContent.includes("<skipped")) {
      skipped++;
    } else {
      passed++;
    }
  }

  return { tests, passed, failed, skipped, duration: totalDuration };
}

